#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use PDF::Text::Simple;

# Function to extract text from a PDF file
sub extract_text {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $pages = $pdf->pages;
    my $text = '';

    for (my $i = 1; $i <= $pages; $i++) {
        my $page = $pdf->page($i);
        my $text_layer = $page->text_layer;
        $text .= $text_layer->text;
    }

    return $text;
}

# Function to find specific information in the extracted text
sub find_info {
    my ($text) = @_;
    my ($date, $author, $tables) = ('', '', []);

    # Find date (assuming it's in a specific format like "Date: 2023-10-01")
    if ($text =~ /Date:\s*(\d{4}-\d{2}-\d{2})/) {
        $date = $1;
    }

    # Find author (assuming it's in a specific format like "Author: John Doe")
    if ($text =~ /Author:\s*(\w+\s+\w+)/) {
        $author = $1;
    }

    # Find tables (assuming tables are enclosed in specific delimiters like "[table: ... ]")
    while ($text =~ /(?<=\[table:\s*)[\s\S]*?(?=\s*\]\s*)/g) {
        push @$tables, $&;
    }

    return ($date, $author, $tables);
